sparql:
SELECT ?film WHERE {
  ?film rdfs:label "Blue Jasmine" @en .
  ?film wdt:P166 ?award .
  ?award rdfs:label "Academy Award for Best Actress" @en
}

SELECT ?releaseDate WHERE {
  wd:Q108072305 wdt:P437 wd:Q6473564 ; wdt:P577 ?releaseDate
}

SELECT ?film WHERE {
  ?film rdfs:label "Mad Max Beyond Thunderdome" @en .
}

SELECT ?film WHERE {
  ?film wdt:P57 wd:Q103917 .
  ?film wdt:P577 ?releaseDate .
  FILTER(strstarts(str(?releaseDate) , "2001"))
}

SELECT DISTINCT ?worldCupEvent ?worldCupYear WHERE {
  wd:Q188228 wdt:P1344 ?worldCupEvent .
  ?worldCupEvent wdt:P585 ?worldCupYear .
}
ORDER BY ?worldCupYear
LIMIT 1

SELECT ?club WHERE {
  wd:Q531814 wdt:P54 ?club .
  FILTER(?club = wd:Q1543)
}

SELECT(COUNT(*) AS ?count) WHERE {
  ?event wdt:P31 wd:Q7965 .
  ?event wdt:P585 ?date .
  ?event wdt:P3764 wd:Q9673 .
  FILTER(YEAR(?date) >= 2016)
}

SELECT ?film ?filmLabel WHERE {
  ?film wdt:P31 wd:Q11424 .
  ?film rdfs:label ?filmLabel .
  FILTER(CONTAINS(STR(?filmLabel) , 'Star Wars') && CONTAINS(STR(?filmLabel) , 'Episode I'))
}

SELECT ?award WHERE {
  wd:Q51023 wdt:P1411 ?award .
  FILTER(?award = wd:Q24241)
}

SELECT ?band ?countryLabel WHERE {
  wd:Q1130624 wdt:P495 ?country .
  ?country rdfs:label ?countryLabel .
  FILTER(lang(?countryLabel) = "en")
}

SELECT ?club WHERE {
  wd:Q11584 wdt:P54 ?club .
  ?club rdfs:label ?label .
  FILTER(lang(?label) = 'en')
}

SELECT ?title ?publicationDate WHERE {
  wd:Q7173181 wdt:P1476 ?title .
  wd:Q7173181 wdt:P577 ?publicationDate .
}

SELECT ?film ?collection WHERE {
  ?film wdt:P2142 ?collection .
  FILTER(?film = wd:Q162255 || ?film = wd:Q170564 || ?film = wd:Q29054009 || ?film = wd:Q191543)
}

SELECT ?museum WHERE {
  ?museum wdt:P31 wd:Q207694 .
  ?museum wdt:P17 wd:Q27 .
}

SELECT ?actor WHERE {
  ?actor wdt:P166 wd:Q103916 .
  ?actor wdt:P166 wd:Q106291 .
  ?actor wdt:P31 wd:Q5 .
}

SELECT ?party ?label WHERE {
  ?party wdt:P17 wd:Q36 .
  ?party wdt:P31 wd:Q7278 .
  ?party rdfs:label ?label .
  FILTER(LANG(?label) = "en")
}

SELECT ?book ?publicationDate WHERE {
  ?book wdt:P577 ?publicationDate .
  FILTER(?book = wd:Q752584 || ?book = wd:Q478016)
}
ORDER BY ?publicationDate

SELECT ?club(rdfs:label AS ?label) WHERE {
  VALUES ?club {
    wd:Q170703 wd:Q15799
  }
}

SELECT ?film ?reviewScore ?rottentomatoesID WHERE {
  ?film wdt:P444 ?reviewScore .
  ?film wdt:P1258 ?rottentomatoesID .
  FILTER(?film = wd:Q217020 || ?film = wd:Q1201853 || ?film = wd:Q22665878)
}

SELECT(COUNT(?match) AS ?matchCount) WHERE {
  wd:Q27049064 wdt:P1532 wd:Q142 .
  wd:Q27049064 wdt:P1350 ?match
}

SELECT ?season ?races WHERE {
  ?season wdt:P1350 ?races .
  FILTER(?season = wd:Q69913 || ?season = wd:Q14293115 || ?season = wd:Q20755615 || ?season = wd:Q23051084 || ?season = wd:Q41173535)
}

SELECT ?season ?races WHERE {
  ?season wdt:P1346 wd:Q9673 ; wdt:P1350 ?races
}
ORDER BY DESC(?races)

SELECT ?book ?title ?publicationDate WHERE {
  wd:Q483412 wdt:P527 ?book .
  ?book wdt:P1476 ?title .
  OPTIONAL {
    ?book wdt:P577 ?publicationDate
  }
}
ORDER BY ?publicationDate

SELECT ?college ?foundingDate WHERE {
  ?college wdt:P571 ?foundingDate .
  FILTER(?college = wd:Q13371 || ?college = wd:Q49112 || ?college = wd:Q49117 || ?college = wd:Q21578 || ?college = wd:Q49088 || ?college = wd:Q49116 || ?college = wd:Q49115 || ?college = wd:Q49114)
}
ORDER BY ?foundingDate

SELECT(COUNT(?cup) AS ?title_count) WHERE {
  wd:Q620722 wdt:P118 ?cup .
  ?cup wdt:P118 wd:Q27192
}

SELECT DISTINCT ?actor ?actorLabel WHERE {
  wd:Q936327 wdt:P161 ?actor .
  ?actor wdt:P31 wd:Q5 .
  OPTIONAL {
    ?actor rdfs:label ?actorLabel .
  }
  FILTER(lang(?actorLabel) = 'en')
}

SELECT ?country ?language WHERE {
  VALUES ?country {
    wd:Q20 wd:Q34 wd:Q35
  }
  ?country wdt:P37 ?language .
}

SELECT(COUNT(?final) AS ?number_of_appearances) WHERE {
  wd:Q2521385 wdt:P1350 ?final .
  wd:Q249679 wdt:P1350 ?final .
}

SELECT ?season ?numRaces WHERE {
  ?season rdfs:label ?label .
  FILTER(CONTAINS(STR(?label) , "2000 Formula One World Championship"))
  ?season wdt:P1350 ?numRaces .
}
ORDER BY ?numRaces

SELECT ?member ?birthDate ?birthPlace WHERE {
  ?member wdt:P569 ?birthDate .
  ?member wdt:P19 ?birthPlace .
}
VALUES ?member {
  wd:Q1203 wd:Q2599 wd:Q2643 wd:Q2632
}

SELECT ?group ?groupLabel ?languages ?religions WHERE {
  VALUES ?group {
    wd:Q42740 wd:Q862086 wd:Q4172847 wd:Q161652 wd:Q484464
  }
  ?group rdfs:label ?groupLabel .
  ?group wdt:P1412 ?languages .
  ?group wdt:P140 ?religions .
  FILTER(lang(?groupLabel) = 'en')
}

SELECT ?subject(STR(?object) AS ?matches) WHERE {
  ?subject wdt:P1350 ?object .
  FILTER(?subject = wd:Q1835)
}

SELECT ?series1 ?series2 ?games1 ?games2(ABS(?games1 - ?games2) AS ?difference) WHERE {
  ?series1 wdt:P1350 ?games1 .
  ?series2 wdt:P1350 ?games2 .
  ?series1 rdfs:label "2008 National League Championship Series" @en .
  ?series2 rdfs:label "1977 National League Championship Series" @en
}

SELECT ?team(COUNT(?final) AS ?appearances) WHERE {
  ?team wdt:P1350 ?final .
}
GROUP BY ?team
ORDER BY ?appearances
LIMIT 3

SELECT ?book ?bookLabel WHERE {
  wd:Q4470 wdt:P527 ?book .
  ?book wdt:P1476 ?bookTitle .
  FILTER(langMatches(lang(?bookTitle) , 'en'))
}
LIMIT 1

SELECT ?actor(COUNT(?film) AS ?count) WHERE {
  ?film wdt:P161 ?actor .
  ?film wdt:P161 wd:Q227129 .
}
GROUP BY ?actor
HAVING(?count > 2)

SELECT ?actor ?actorLabel WHERE {
  wd:Q80379 wdt:P161 ?actor .
  ?actor rdfs:label ?actorLabel .
  FILTER(LANG(?actorLabel) = "en")
}

SELECT ?ranking WHERE {
  wd:Q134479 wdt:P1352 ?ranking .
  wd:Q134479 wdt:P1344 wd:Q170645 .
}
LIMIT 1

SELECT ?team ?goals WHERE {
  wd:Q69622172 wdt:P1923 ?team .
  wd:Q69622172 wdt:P1351 ?goals
}

SELECT ?dynasty ?ethnicityLabel ?originLabel WHERE {
  ?dynasty wdt:P172 ?ethnicity .
  ?ethnicity rdfs:label ?ethnicityLabel .
  FILTER(CONTAINS(STR(?ethnicityLabel) , "Nubian") || CONTAINS(STR(?ethnicityLabel) , "Libyan") || CONTAINS(STR(?ethnicityLabel) , "Hyksos"))
  OPTIONAL {
    ?dynasty wdt:P495 ?origin .
    ?origin rdfs:label ?originLabel .
  }
}
LIMIT 10

SELECT ?startYear ?endYear WHERE {
  wd:Q75984 wdt:P580 ?startYear .
  wd:Q75984 wdt:P582 ?endYear .
}

SELECT ?mvpWinner ?superBowl WHERE {
  ?mvpWinner wdt:P166 wd:Q289678 .
  ?mvpWinner wdt:P1344 ?superBowl .
  ?superBowl rdfs:label ?superBowlLabel .
  FILTER(CONTAINS(STR(?superBowlLabel) , "Super Bowl"))
}

SELECT ?player ?birthCountry WHERE {
  ?player wdt:P54 wd:Q162954 .
  ?player wdt:P19 ?placeOfBirth .
  ?placeOfBirth wdt:P17 ?birthCountry
}

SELECT ?game ?duration WHERE {
  ?game wdt:P2047 ?duration .
  ?game ?p ?team1 .
  ?team1 wdt:P118 wd:Q858082 .
  ?team2 wdt:P118 wd:Q858082
}

SELECT ?series(MAX(?attendance) AS ?max_attendance) WHERE {
  ?series wdt:P1110 ?attendance .
  ?series(wdt:P1110) ?attendance .
}
GROUP BY ?series

SELECT ?careerStart ?team WHERE {
  wd:Q192707 wdt:P2031 ?careerStart .
  wd:Q192707 wdt:P54 ?team .
}

SELECT ?player(MAX(?caps) AS ?max_caps) WHERE {
  ?player wdt:P1350 ?caps .
}
GROUP BY ?player

SELECT ?club WHERE {
  ?club rdfs:label "New York City FC" @en
}

SELECT ?pm ?eventLabel WHERE {
  ?pm wdt:P39 wd:Q14211 .
  ?pm wdt:P793 ?event .
  ?event rdfs:label ?eventLabel .
  FILTER(langMatches(lang(?eventLabel) , "en"))
}

SELECT ?work ?workLabel WHERE {
  wd:Q5686 wdt:P800 ?work .
  ?work rdfs:label ?workLabel .
  FILTER(lang(?workLabel) = 'en')
}
LIMIT 10

SELECT ?character(STR(?character) AS ?name) WHERE {
  wd:Q208094 wdt:P674 ?character .
  ?character wdt:P31 wd:Q3658341 .
}

SELECT ?deity ?label WHERE {
  VALUES ?deity {
    wd:Q1252904 wd:Q37340 wd:Q219412 wd:Q654596
  }
  ?deity rdfs:label ?label .
}

SELECT ?city(str(?pop) AS ?population) WHERE {
  ?city wdt:P1082 ?pop .
  FILTER(?city = wd:Q1645)
}

SELECT ?country ?matchCount WHERE {
  wd:Q214204 wdt:P1532 ?country .
  wd:Q214204 wdt:P1350 ?matchCount
}

SELECT ?dam ?country WHERE {
  ?dam wdt:P366 wd:Q80638 .
  ?dam wdt:P17 ?country .
  Filter(?country != wd:Q413563)
}

SELECT ?script(COUNT(?language) AS ?languageCount) WHERE {
  ?language wdt:P282 ?script .
}
GROUP BY ?script
HAVING(COUNT(?language) > 1)

SELECT ?series ?venue WHERE {
  ?series wdt:P276 ?venue .
  FILTER(?series = wd:Q56692089 || ?series = wd:Q14870260 || ?series = wd:Q3511178)
}

SELECT ?country ?building ?height ?location WHERE {
  ?building wdt:P276 ?country .
  ?building wdt:P2048 ?height .
  VALUES ?country {
    wd:Q262 wd:Q1028 wd:Q948 wd:Q1016 wd:Q79 wd:Q851 wd:Q794 wd:Q796
  }
}
ORDER BY DESC(?height)

SELECT ?shoppingMall WHERE {
  wd:Q1686 wdt:P1082 ?population .
  ?shoppingMall wdt:P131 wd:Q1686
}

SELECT ?driver ?team ?wins ?year WHERE {
  ?driver wdt:P1355 ?wins .
  ?driver wdt:P571 ?year .
  optional {
    ?team wdt:P1355 ?wins .
    ?team wdt:P571 ?year .
  }
  FILTER(?year > 2015 && ?driver = wd:Q9673 || ?team = wd:Q172721)
}

SELECT ?country(COUNT(?company) AS ?numCompanies) WHERE {
  ?company wdt:P17 ?country .
  ?company wdt:P2139 ?revenue
}
GROUP BY ?country

SELECT ?leader(STR(?leader) AS ?leaderLabel)(STR(?party) AS ?partyLabel)(YEAR(?birthDate) AS ?birthYear)(YEAR(?birthDate) - 2023 AS ?age) WHERE {
  ?leader wdt:P488 ?party .
  ?leader wdt:P569 ?birthDate .
  ?party wdt:P1387 ?politicalAlignment .
  FILTER(YEAR(?birthDate) >= 1973 && YEAR(?birthDate) <= 1983)
}

SELECT ?episode ?episodeLabel WHERE {
  wd:Q552314 wdt:P1811 ?episode .
  ?episode rdfs:label ?episodeLabel .
  FILTER(lang(?episodeLabel) = 'en')
}
ORDER BY ?episodeLabel

SELECT ?person ?causeOfDeath WHERE {
  ?person wdt:P39 wd:Q13218630 .
  ?person wdt:P69 wd:Q846173 .
  ?person wdt:P607 ?conflict .
  ?person wdt:P509 ?causeOfDeath .
}

SELECT ?movie ?duration WHERE {
  ?movie wdt:P2047 ?duration .
  FILTER(?movie = wd:Q41567 || ?movie = wd:Q2875)
}

SELECT ?birthplace(COUNT(*) AS ?count) WHERE {
  ?pm wdt:P19 ?birthplace .
}
GROUP BY ?birthplace
ORDER BY DESC(?count)
LIMIT 1

SELECT ?founder(YEAR(?foundingYear) - YEAR(?birthYear) AS ?age) WHERE {
  ?company wdt:P108 ?foundingYear .
  ?founder wdt:P106 ?company .
  ?founder wdt:P102 ?birthYear
}

SELECT ?person WHERE {
  ?person wdt:P39 wd:Q14213 .
  ?person rdfs:label ?label .
  FILTER(LANG(?label) = 'en')
}

SELECT ?item ?start WHERE {
  ?item wdt:P580 ?start .
  FILTER(ISBLANK(?start) = false)
}
LIMIT 10

SELECT ?ethnicGroup(STR(?pop) AS ?population)(STR(?lang) AS ?languages)(STR(?rel) AS ?religion)(STR(?cnt) AS ?country) WHERE {
  ?ethnicGroup wdt:P140 ?rel .
  ?ethnicGroup wdt:P1412 ?lang .
  ?ethnicGroup wdt:P17 ?cnt .
  ?ethnicGroup wdt:P1082 ?pop .
}

SELECT ?country(COUNT(*) AS ?count) WHERE {
  ?powerPlant wdt:P31 wd:Q134447 .
  ?powerPlant wdt:P131 ?country .
}
GROUP BY ?country
HAVING(?count > 3)

SELECT ?population2000 ?population2009 WHERE {
  wd:Q368526 wdt:P1082 ?population2000 .
  wd:Q368526 wdt:P1082 ?population2009 .
}

SELECT ?country(GROUP_CONCAT(?ethnicGroup) AS ?ethnicGroups) WHERE {
  ?country wdt:P172 ?ethnicGroup .
}
GROUP BY ?country

SELECT ?song ?publicationDate ?distributionFormat WHERE {
  ?song wdt:P577 ?publicationDate .
  ?song wdt:P437 ?distributionFormat .
  ?song rdfs:label "Into You" @en
}

SELECT ?player ?age WHERE {
  ?player wdt:P569 ?birthDate .
  BIND(2024 - YEAR(?birthDate) AS ?age)
  FILTER(?age > 35)
}

SELECT ?book ?pubdate WHERE {
  ?book wdt:P179 wd:Q5400672 .
  ?book wdt:P577 ?pubdate .
  FILTER(?book = wd:Q3427960)
}

SELECT ?pandemic WHERE {
  ?pandemic wdt:P138 ?cause .
  FILTER(NOT EXISTS {
    ?pandemic wdt:P828 ?warCause .
    ?warCause rdfs:label "war" @en
  })
}

SELECT DISTINCT ?year WHERE {
  ?ship wdt:P729 ?year .
  ?ship wdt:P31 wd:Q177597 .
}

SELECT ?country(CONCAT(?countryLabel , ' - national dish unknown') AS ?nationalDish) WHERE {
  ?country wdt:P17 wd:Q27509 .
}

SELECT ?opponent WHERE {
  wd:Q388232 wdt:P1344 wd:Q911847 .
  wd:Q334526 wdt:P1344 wd:Q911847 .
}
